import React, { useState } from 'react';
import { FaSearch, FaFilter } from 'react-icons/fa';
import '../../styles/Courses.css';
import '../../styles/SearchBar.css';

const SearchBar = ({ placeholder, onSearch, showFilters = true }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showFilterOptions, setShowFilterOptions] = useState(false);

  const handleSearch = (e) => {
    const value = e.target.value;
    setSearchTerm(value);
    onSearch(value);
  };

  const filterOptions = [
    'All Categories',
    'Design',
    'Development',
    'Data Science',
    'DevOps',
    'Beginner',
    'Intermediate',
    'Advanced'
  ];

  return (
    <div className="search-container">
      <div className="search-bar">
        <FaSearch className="search-icon" />
        <input
          type="text"
          placeholder={placeholder || "Search courses..."}
          value={searchTerm}
          onChange={handleSearch}
          className="search-input"
        />
        
        {showFilters && (
          <div className="filter-wrapper">
            <button 
              className="filter-btn"
              onClick={() => setShowFilterOptions(!showFilterOptions)}
            >
              <FaFilter />
              Filter
            </button>
            
            {showFilterOptions && (
              <div className="filter-dropdown">
                {filterOptions.map((option, index) => (
                  <label key={index} className="filter-option">
                    <input type="checkbox" />
                    <span>{option}</span>
                  </label>
                ))}
                <div className="filter-actions">
                  <button className="btn btn-sm">Apply</button>
                  <button 
                    className="btn btn-sm btn-outline"
                    onClick={() => setShowFilterOptions(false)}
                  >
                    Cancel
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Search suggestions */}
      {searchTerm && (
        <div className="search-suggestions">
          <div className="suggestion-item">
            <FaSearch className="suggestion-icon" />
            <span>Web Development Bootcamp</span>
          </div>
          <div className="suggestion-item">
            <FaSearch className="suggestion-icon" />
            <span>Computer Programming Basics</span>
          </div>
          <div className="suggestion-item">
            <FaSearch className="suggestion-icon" />
            <span>Computer Science Fundamentals</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default SearchBar;
